  __vite_style__.textContent = "@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;600;700&family=Inter:wght@400;500;600&display=swap');\n\n\n/* ============================================================\n   Miris-Babylon-Bridge — index.css\n   Dark cyberpunk HUD aesthetic\n   ============================================================ */\n*, *::before, *::after {\n  box-sizing: border-box;\n  margin: 0;\n  padding: 0;\n}\n:root {\n  --cyan:        #00f5ff;\n  --cyan-dim:    #00b8c4;\n  --green:       #39ff14;\n  --red:         #ff2d55;\n  --bg:          rgba(8, 12, 20, 0.85);\n  --bg-border:   rgba(0, 245, 255, 0.18);\n  --text:        #c8d8e8;\n  --text-dim:    #5a7080;\n  --mono:        'JetBrains Mono', 'Courier New', monospace;\n  --sans:        'Inter', system-ui, sans-serif;\n}\nhtml, body, #root {\n  width: 100%;\n  height: 100%;\n  overflow: hidden;\n  background: transparent;\n  font-family: var(--mono);\n}\n/* ============================================================\n   Debug HUD\n   ============================================================ */\n.hud {\n  position: fixed;\n  top: 20px;\n  right: 20px;\n  z-index: 10000;\n  min-width: 220px;\n  padding: 14px 18px;\n  background: var(--bg);\n  border: 1px solid var(--bg-border);\n  border-radius: 10px;\n  backdrop-filter: blur(12px);\n  box-shadow:\n    0 0 24px rgba(0, 245, 255, 0.08),\n    inset 0 1px 0 rgba(255, 255, 255, 0.05);\n  pointer-events: none; /* HUD doesn't capture clicks */\n  user-select: none;\n  animation: hud-in 0.35s cubic-bezier(0.22, 1, 0.36, 1) both;\n}\n@keyframes hud-in {\n  from { opacity: 0; transform: translateX(12px); }\n  to   { opacity: 1; transform: translateX(0); }\n}\n.hud--falsified {\n  border-color: rgba(255, 45, 85, 0.4);\n  box-shadow:\n    0 0 24px rgba(255, 45, 85, 0.15),\n    inset 0 1px 0 rgba(255, 255, 255, 0.05);\n}\n/* Title row */\n.hud__title {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  font-family: var(--sans);\n  font-size: 10px;\n  font-weight: 600;\n  letter-spacing: 0.12em;\n  text-transform: uppercase;\n  color: var(--cyan);\n  margin-bottom: 12px;\n  padding-bottom: 10px;\n  border-bottom: 1px solid var(--bg-border);\n}\n.hud__dot {\n  width: 7px;\n  height: 7px;\n  border-radius: 50%;\n  background: var(--cyan);\n  box-shadow: 0 0 6px var(--cyan);\n  animation: pulse-dot 2s ease-in-out infinite;\n  flex-shrink: 0;\n}\n.hud--falsified .hud__dot {\n  background: var(--red);\n  box-shadow: 0 0 6px var(--red);\n}\n@keyframes pulse-dot {\n  0%, 100% { opacity: 1; }\n  50%       { opacity: 0.3; }\n}\n/* Stat rows */\n.hud__row {\n  display: flex;\n  justify-content: space-between;\n  align-items: baseline;\n  gap: 12px;\n  margin-bottom: 6px;\n}\n.hud__label {\n  font-size: 11px;\n  color: var(--text-dim);\n  letter-spacing: 0.04em;\n}\n.hud__value {\n  font-size: 13px;\n  font-weight: 600;\n  color: var(--text);\n  letter-spacing: 0.02em;\n}\n.hud__value--count {\n  color: var(--cyan);\n  font-size: 15px;\n  text-shadow: 0 0 8px rgba(0, 245, 255, 0.5);\n  transition: color 0.2s;\n}\n/* Status badges */\n.hud__warning,\n.hud__success {\n  margin-top: 10px;\n  padding: 5px 8px;\n  border-radius: 5px;\n  font-size: 10px;\n  font-weight: 700;\n  letter-spacing: 0.08em;\n  text-align: center;\n}\n.hud__warning {\n  background: rgba(255, 45, 85, 0.12);\n  border: 1px solid rgba(255, 45, 85, 0.3);\n  color: var(--red);\n}\n.hud__success {\n  background: rgba(57, 255, 20, 0.08);\n  border: 1px solid rgba(57, 255, 20, 0.25);\n  color: var(--green);\n  animation: success-glow 2s ease-in-out infinite;\n}\n@keyframes success-glow {\n  0%, 100% { box-shadow: 0 0 0 rgba(57, 255, 20, 0); }\n  50%       { box-shadow: 0 0 10px rgba(57, 255, 20, 0.2); }\n}\n";
